```java
import java.util.Scanner;

class Point3D {
    double x, y, z;

    public Point3D(double x, double y, double z) {
        this.x = x;
        this.y = y;
        this.z = z;
    }

    public Point3D add(Point3D other) {
        return new Point3D(x + other.x, y + other.y, z + other.z);
    }

    public Point3D subtract(Point3D other) {
        return new Point3D(x - other.x, y - other.y, z - other.z);
    }

    public Point3D multiply(double scalar) {
        return new Point3D(x * scalar, y * scalar, z * scalar);
    }

    public Point3D divide(double scalar) {
        if (scalar == 0) {
            throw new ArithmeticException("Cannot divide by zero!");
        }
        return new Point3D(x / scalar, y / scalar, z / scalar);
    }

    public double magnitude() {
        return Math.sqrt(x * x + y * y + z * z);
    }

    public double dotProduct(Point3D other) {
        return x * other.x + y * other.y + z * other.z;
    }

    public Point3D crossProduct(Point3D other) {
        return new Point3D(
            y * other.z - z * other.y,
            z * other.x - x * other.z,
            x * other.y - y * other.x
        );
    }

    @Override
    public String toString() {
        return "(" + x + ", " + y + ", " + z + ")";
    }
}

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("3D Calculator");
        System.out.println("1. Addition");
        System.out.println("2. Subtraction");
        System.out.println("3. Multiplication");
        System.out.println("4. Division");
        System.out.println("5. Magnitude");
        System.out.println("6. Dot Product");
        System.out.println("7. Cross Product");

        System.out.print("Enter your choice: ");
        int choice = scanner.nextInt();

        switch (choice) {
            case 1:
                System.out.print("Enter first point coordinates (x y z): ");
                double x1 = scanner.nextDouble();
                double y1 = scanner.nextDouble();
                double z1 = scanner.nextDouble();
                System.out.print("Enter second point coordinates (x y z): ");
                double x2 = scanner.nextDouble();
                double y2 = scanner.nextDouble();
                double z2 = scanner.nextDouble();
                Point3D point1 = new Point3D(x1, y1, z1);
                Point3D point2 = new Point3D(x2, y2, z2);
                Point3D result = point1.add(point2);
                System.out.println("Result: " + result);
                break;

            case 2:
                System.out.print("Enter first point coordinates (x y z): ");
                x1 = scanner.nextDouble();
                y1 = scanner.nextDouble();
                z1 = scanner.nextDouble();
                System.out.print("Enter second point coordinates (x y z): ");
                x2 = scanner.nextDouble();
                y2 = scanner.nextDouble();
                z2 = scanner.nextDouble();
                point1 = new Point3D(x1, y1, z1);
                point2 = new Point3D(x2, y2, z2);
                result = point1.subtract(point2);
                System.out.println("Result: " + result);
                break;

            case 3:
                System.out.print("Enter point coordinates (x y z): ");
                x1 = scanner.nextDouble();
                y1 = scanner.nextDouble();
                z1 = scanner.nextDouble();
                System.out.print("Enter scalar value: ");
                double scalar = scanner.nextDouble();
                point1 = new Point3D(x1, y1, z1);
                result = point1.multiply(scalar);
                System.out.println("Result: " + result);
                break;

            case 4:
                System.out.print("Enter point coordinates (x y z): ");
                x1 = scanner.nextDouble();
                y1 = scanner.nextDouble();
                z1 = scanner.nextDouble();
                System.out.print("Enter scalar value: ");
                scalar = scanner.nextDouble();
                point1 = new Point3D(x1, y1, z1);
                try {
                    result = point1.divide(scalar);
                    System.out.println("Result: " + result);
                } catch (ArithmeticException e) {
                    System.out.println(e.getMessage());
                }
                break;

            case 5:
                System.out.print("Enter point coordinates (x y z): ");
                x1 = scanner.nextDouble();
                y1 = scanner.nextDouble();
                z1 = scanner.nextDouble();
                point1 = new Point3D(x1, y1, z1);
                System.out.println("Result: " + point1.magnitude());
                break;

            case 6:
                System.out.print("Enter first point coordinates (x y z): ");
                x1 = scanner.nextDouble();
                y1 = scanner.nextDouble();
                z1 = scanner.nextDouble();
                System.out.print("Enter second point coordinates (x y z): ");
                x2 = scanner.nextDouble();
                y2 = scanner.nextDouble();
                z2 = scanner.nextDouble();
                point1 = new Point3D(x1, y1, z1);
                point2 = new Point3D(x2, y2, z2);
                System.out.println("Result: " + point1.dotProduct(point2));
                break;

            case 7:
                System.out.print("Enter first point coordinates (x y z): ");
                x1 = scanner.nextDouble();
                y1 = scanner.nextDouble();
                z1 = scanner.nextDouble();
                System.out.print("Enter second point coordinates (x y z): ");
                x2 = scanner.nextDouble();
                y2 = scanner.nextDouble();
                z2 = scanner.nextDouble();
                point1 = new Point3D(x1, y1, z1);
                point2 = new Point3D(x2, y2, z2);
                result = point1.crossProduct(point2);
                System.out.println("Result: " + result);
                break;

            default:
                System.out.println("Invalid choice. Please try again.");
        }
    }
}
```

